class Solution {
public:
    vector<long long> unmarkedSumArray(vector<int>& nums, vector<vector<int>>& queries) {
        int n = nums.size();
        vector<long long> ans;
        vector<bool> marked(n, false);
        long long total = 0;
        for (int x : nums) total += x;

        set<pair<int,int>> st;
        for (int i = 0; i < n; ++i) st.insert({nums[i], i});

        for (auto& q : queries) {
            int idx = q[0], k = q[1];
            if (!marked[idx]) {
                marked[idx] = true;
                total -= nums[idx];
                st.erase({nums[idx], idx});
            }
            while (k && !st.empty()) {
                auto it = st.begin();
                int val = it->first, pos = it->second;
                st.erase(it);
                marked[pos] = true;
                total -= val;
                --k;
            }
            ans.push_back(total);
        }
        return ans;
    }
};
```
efficiency: HIGH
time complexity: O((n + m) log n)
space complexity: O(n)
energy implications: LOW
explanation: Maintain a running total of unmarked elements and a balanced set ordered by (value, index). Each query marks the specified index (if unmarked) and then the k smallest unmarked elements via set operations. Each element is inserted and erased at most once, giving O(log n) per operation.

